// Dremplay One example world v1: immutable 3 km × 3 km, 8 m control lattice.
(()=>{const encoded='';globalThis.DREMPLAY_EXAMPLE_WORLD_READY=(async()=>{if(typeof DecompressionStream==='undefined')throw new Error('This browser cannot decode the pre-baked world atlas.');const packed=new Uint8Array(encoded.length*3/4|0);let length=0;for(let at=0;at<encoded.length;at+=32768){const raw=atob(encoded.slice(at,Math.min(encoded.length,at+32768)));for(let i=0;i<raw.length;i++)packed[length++]=raw.charCodeAt(i);}const stream=new Blob([packed.subarray(0,length)]).stream().pipeThrough(new DecompressionStream('deflate')),bytes=new Uint8Array(await new Response(stream).arrayBuffer());if(bytes.length!==1131008)throw new Error('Pre-baked world atlas failed its length check.');globalThis.DREMPLAY_EXAMPLE_WORLD=Object.freeze({name:'Long Island Example',version:1,size:376,stride:8,stepVoxels:80,minVoxel:-15000,maxVoxel:15000,bytes});return globalThis.DREMPLAY_EXAMPLE_WORLD;})();})();
